namespace sv_ad7e56c0c9d24ea4a7b55921ea707062.Services;

public class WarehouseState
{
    public static readonly IReadOnlyList<(string Id, string Name)> Warehouses =
    [
        ("WH-001", "Warehouse A – Downtown"),
        ("WH-002", "Warehouse B – Airport"),
        ("WH-003", "Warehouse C – Harbor"),
    ];

    public string CurrentWarehouseId { get; private set; } = Warehouses[0].Id;

    public string CurrentWarehouseName =>
        Warehouses.First(w => w.Id == CurrentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (warehouseId == CurrentWarehouseId) return;
        CurrentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_ad7e56c0c9d24ea4a7b55921ea707062.Services;

/// <summary>
/// Holds the latest low-stock alert count so that both the dashboard page
/// and the sidebar badge can stay in sync without independent polling.
/// Scoped per circuit — each user gets their own instance.
/// </summary>
public class AlertState
{
    public int LowStockCount { get; private set; }

    public event Action? OnChange;

    public void UpdateCount(int count)
    {
        if (count == LowStockCount) return;
        LowStockCount = count;
        OnChange?.Invoke();
    }
}

namespace sv_ad7e56c0c9d24ea4a7b55921ea707062.Services;

public class InventoryAlertService
{
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate a database query — return a random count between 0 and 15.
        return Task.FromResult(Random.Shared.Next(0, 16));
    }
}

