@rendermode InteractiveServer

@using sv_ad7e56c0c9d24ea4a7b55921ea707062.Services
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="d-flex align-items-center gap-2">
    <label class="form-label mb-0 text-nowrap fw-semibold" for="warehouse-select">
        🏭 Warehouse:
    </label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            style="width: 260px;"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.Warehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        WarehouseState.SetWarehouse(e.Value?.ToString() ?? WarehouseState.Warehouses[0].Id);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@rendermode InteractiveServer

@using sv_ad7e56c0c9d24ea4a7b55921ea707062.Services
@inject AlertState AlertState
@implements IDisposable

@if (AlertState.LowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@AlertState.LowStockCount</span>
}

@code {
    protected override void OnInitialized()
    {
        AlertState.OnChange += OnAlertChanged;
    }

    private void OnAlertChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertState.OnChange -= OnAlertChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer

@using sv_ad7e56c0c9d24ea4a7b55921ea707062.Services
@inject WarehouseState WarehouseState
@inject AlertState AlertState
@inject InventoryAlertService InventoryAlertService
@implements IDisposable

<PageTitle>Dashboard – @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>📊 Warehouse Dashboard</h1>

<div class="alert alert-info">
    Currently managing: <strong>@WarehouseState.CurrentWarehouseName</strong>
    <span class="text-muted">(@WarehouseState.CurrentWarehouseId)</span>
</div>

<div class="row g-4 mb-4">
    <div class="col-md-4">
        <div class="card @(AlertState.LowStockCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4 @(AlertState.LowStockCount > 0 ? "text-danger" : "text-success")">
                    @AlertState.LowStockCount
                </p>
                <p class="text-muted mb-0">
                    items below minimum level
                </p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="mb-1">
                    @if (_isPolling)
                    {
                        <span class="badge bg-success">● Active</span>
                    }
                    else
                    {
                        <span class="badge bg-secondary">○ Inactive</span>
                    }
                </p>
                <p class="text-muted mb-0">refreshes every 10 s</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Last Checked</h5>
                <p class="display-6">@(_lastChecked?.ToString("HH:mm:ss") ?? "—")</p>
                <p class="text-muted mb-0">server time</p>
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private bool _isPolling;
    private DateTime? _lastChecked;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await StartPollingAsync();
        }
    }

    private async void OnWarehouseChanged()
    {
        // Restart polling immediately for the new warehouse.
        await StopPollingAsync();
        await InvokeAsync(async () =>
        {
            StateHasChanged();
            await StartPollingAsync();
        });
    }

    private async Task StartPollingAsync()
    {
        _cts = new CancellationTokenSource();
        _isPolling = true;
        var token = _cts.Token;

        // Initial fetch right away.
        await PollOnceAsync();

        _ = Task.Run(async () =>
        {
            using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            try
            {
                while (await timer.WaitForNextTickAsync(token))
                {
                    await InvokeAsync(async () =>
                    {
                        await PollOnceAsync();
                    });
                }
            }
            catch (OperationCanceledException) { }
        }, token);
    }

    private async Task PollOnceAsync()
    {
        var count = await InventoryAlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lastChecked = DateTime.Now;
        AlertState.UpdateCount(count);
        StateHasChanged();
    }

    private Task StopPollingAsync()
    {
        _isPolling = false;
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

